/**
 * Webhook notification handler — fires HTTP callbacks when order events occur.
 *
 * Integrates with the EventBus pattern: subscribes to order events and
 * dispatches webhook payloads to registered URLs. External consumers
 * register URLs for specific event types via the webhook registry.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type { EventType, OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface WebhookRegistration {
  id: string;
  url: string;
  eventType: EventType;
  secret?: string;
  createdAt: Date;
}

export interface WebhookDelivery {
  id: string;
  webhookId: string;
  url: string;
  eventType: EventType;
  payload: WebhookPayload;
  success: boolean;
  statusCode?: number;
  error?: string;
  deliveredAt: Date;
}

export interface WebhookPayload {
  event: EventType;
  timestamp: string;
  data: Record<string, unknown>;
}

export type WebhookSender = (url: string, payload: WebhookPayload, secret?: string) => Promise<{ success: boolean; statusCode?: number; error?: string }>;

/**
 * Default sender that performs an HTTP POST. In production this would use
 * fetch/axios; here it's a passthrough so tests can inject a mock.
 */
const defaultSender: WebhookSender = async () => ({
  success: true,
  statusCode: 200,
});

let nextWebhookId = 1;
let nextDeliveryId = 1;

function generateWebhookId(): string {
  return `wh-${String(nextWebhookId++).padStart(4, '0')}`;
}

function generateDeliveryId(): string {
  return `whd-${String(nextDeliveryId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounters(): void {
  nextWebhookId = 1;
  nextDeliveryId = 1;
}

export class WebhookHandler {
  private logger = new Logger('WebhookHandler');
  private registrations: WebhookRegistration[] = [];
  private deliveries: WebhookDelivery[] = [];
  private sender: WebhookSender;

  constructor(
    private eventBus: EventBus,
    sender?: WebhookSender,
  ) {
    this.sender = sender ?? defaultSender;
    this.registerHandlers();
  }

  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', async (event) => {
      await this.dispatchWebhooks('order:created', {
        event: 'order:created',
        timestamp: event.timestamp.toISOString(),
        data: {
          orderId: event.order.id,
          userId: event.order.userId,
          items: event.order.items,
          total: event.order.total,
          status: event.order.status,
        },
      });
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', async (event) => {
      await this.dispatchWebhooks('order:status-changed', {
        event: 'order:status-changed',
        timestamp: event.timestamp.toISOString(),
        data: {
          orderId: event.order.id,
          userId: event.order.userId,
          previousStatus: event.previousStatus,
          newStatus: event.newStatus,
        },
      });
    });
  }

  /**
   * Register a webhook URL for a specific event type.
   */
  registerWebhook(url: string, eventType: EventType, secret?: string): WebhookRegistration {
    const registration: WebhookRegistration = {
      id: generateWebhookId(),
      url,
      eventType,
      secret,
      createdAt: new Date(),
    };
    this.registrations.push(registration);
    this.logger.info(`Webhook registered: ${registration.id} for ${eventType} -> ${url}`);
    return registration;
  }

  /**
   * Unregister a webhook by ID.
   */
  unregisterWebhook(id: string): boolean {
    const index = this.registrations.findIndex((r) => r.id === id);
    if (index < 0) {
      return false;
    }
    this.registrations.splice(index, 1);
    this.logger.info(`Webhook unregistered: ${id}`);
    return true;
  }

  /**
   * Get all registered webhooks.
   */
  getRegistrations(): WebhookRegistration[] {
    return [...this.registrations];
  }

  /**
   * Get registrations for a specific event type.
   */
  getRegistrationsForEvent(eventType: EventType): WebhookRegistration[] {
    return this.registrations.filter((r) => r.eventType === eventType);
  }

  /**
   * Get all delivery records.
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Get deliveries for a specific webhook.
   */
  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
    return this.deliveries.filter((d) => d.webhookId === webhookId);
  }

  /**
   * Clear all registrations and deliveries (useful for testing).
   */
  clear(): void {
    this.registrations = [];
    this.deliveries = [];
  }

  /**
   * Dispatch webhook payloads to all registered URLs for a given event type.
   */
  private async dispatchWebhooks(eventType: EventType, payload: WebhookPayload): Promise<void> {
    const targets = this.registrations.filter((r) => r.eventType === eventType);

    for (const registration of targets) {
      const result = await this.sender(registration.url, payload, registration.secret);

      const delivery: WebhookDelivery = {
        id: generateDeliveryId(),
        webhookId: registration.id,
        url: registration.url,
        eventType,
        payload,
        success: result.success,
        statusCode: result.statusCode,
        error: result.error,
        deliveredAt: new Date(),
      };
      this.deliveries.push(delivery);

      if (result.success) {
        this.logger.info(`Webhook delivered: ${delivery.id} to ${registration.url}`);
      } else {
        this.logger.warn(`Webhook delivery failed: ${delivery.id} to ${registration.url} — ${result.error}`);
      }
    }
  }
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { WebhookHandler, resetWebhookIdCounters } from '../../src/notifications/webhook-handler.js';
import type { WebhookSender, WebhookPayload } from '../../src/notifications/webhook-handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('WebhookHandler', () => {
  let eventBus: EventBus;
  let mockSender: WebhookSender;
  let sentRequests: Array<{ url: string; payload: WebhookPayload; secret?: string }>;
  let handler: WebhookHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    sentRequests = [];
    resetWebhookIdCounters();

    mockSender = vi.fn(async (url, payload, secret) => {
      sentRequests.push({ url, payload, secret });
      return { success: true, statusCode: 200 };
    });

    handler = new WebhookHandler(eventBus, mockSender);
  });

  describe('webhook registration', () => {
    it('should register a webhook and return registration', () => {
      const reg = handler.registerWebhook('https://example.com/hook', 'order:created');

      expect(reg.id).toBe('wh-0001');
      expect(reg.url).toBe('https://example.com/hook');
      expect(reg.eventType).toBe('order:created');
      expect(reg.createdAt).toBeInstanceOf(Date);
    });

    it('should register a webhook with a secret', () => {
      const reg = handler.registerWebhook('https://example.com/hook', 'order:created', 'my-secret');

      expect(reg.secret).toBe('my-secret');
    });

    it('should list all registrations', () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:status-changed');

      expect(handler.getRegistrations()).toHaveLength(2);
    });

    it('should filter registrations by event type', () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:status-changed');
      handler.registerWebhook('https://c.com/hook', 'order:created');

      expect(handler.getRegistrationsForEvent('order:created')).toHaveLength(2);
      expect(handler.getRegistrationsForEvent('order:status-changed')).toHaveLength(1);
    });

    it('should unregister a webhook by ID', () => {
      const reg = handler.registerWebhook('https://a.com/hook', 'order:created');

      expect(handler.unregisterWebhook(reg.id)).toBe(true);
      expect(handler.getRegistrations()).toHaveLength(0);
    });

    it('should return false when unregistering unknown ID', () => {
      expect(handler.unregisterWebhook('wh-9999')).toBe(false);
    });
  });

  describe('order:created webhooks', () => {
    it('should fire webhook when order is created', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date('2026-01-15T10:00:00Z'),
      };

      await eventBus.emit(event);

      expect(sentRequests).toHaveLength(1);
      expect(sentRequests[0]?.url).toBe('https://example.com/hook');
      expect(sentRequests[0]?.payload.event).toBe('order:created');
      expect(sentRequests[0]?.payload.data.orderId).toBe('order-1');
      expect(sentRequests[0]?.payload.data.total).toBe(20);
      expect(sentRequests[0]?.payload.timestamp).toBe('2026-01-15T10:00:00.000Z');
    });

    it('should include order items in payload', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
