          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      const items = sentRequests[0]?.payload.data.items as any[];
      expect(items).toHaveLength(2);
      expect(items[0]?.name).toBe('Widget');
    });

    it('should not fire for unregistered event types', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      expect(sentRequests).toHaveLength(0);
    });
  });

  describe('order:status-changed webhooks', () => {
    it('should fire webhook when order status changes', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date('2026-01-15T12:00:00Z'),
      };

      await eventBus.emit(event);

      expect(sentRequests).toHaveLength(1);
      expect(sentRequests[0]?.payload.event).toBe('order:status-changed');
      expect(sentRequests[0]?.payload.data.previousStatus).toBe('pending');
      expect(sentRequests[0]?.payload.data.newStatus).toBe('confirmed');
      expect(sentRequests[0]?.payload.data.orderId).toBe('order-1');
    });

    it('should fire to multiple registered URLs', async () => {
      handler.registerWebhook('https://a.com/hook', 'order:status-changed');
      handler.registerWebhook('https://b.com/hook', 'order:status-changed');

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      expect(sentRequests).toHaveLength(2);
      expect(sentRequests[0]?.url).toBe('https://a.com/hook');
      expect(sentRequests[1]?.url).toBe('https://b.com/hook');
    });

    it('should pass secret to sender', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed', 'secret-123');

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
